module RefModule(op, a, b, result, zero);input [2:0] op;
  input [15:0] a;
  input [15:0] b;
  output reg [15:0] result; // Changed to reg
  output reg zero;          // Changed to reg

  reg [16:0] final_sig; // to hold intermediate results

  always @* begin
    case(op)
      3'b000: // addition
        final_sig = a + b;
      3'b001: // subtraction
        final_sig = a - b;
      3'b010: // bitwise AND
        final_sig = a & b;
      3'b011: // bitwise OR
        final_sig = a | b;
      3'b100: // bitwise XOR
        final_sig = a ^ b;
      3'b101: // logical shift left
        final_sig = a << b;
      3'b110: // logical shift right
        final_sig = a >> b;
      3'b111: // arithmetic shift right
        final_sig = $signed(a) >>> b;
      default: // safeguard for undefined operations
        final_sig = 0;
    endcase
    result = final_sig[15:0];
    zero = (result == 0);
  end

endmodule
